#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""将 Markdown 文件转换为 Word 文档"""

import re
from docx import Document
from docx.shared import Pt, Inches
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.enum.style import WD_STYLE_TYPE

def markdown_to_docx(input_file, output_file):
    """读取 Markdown 文件并转换为 Word 文档"""

    doc = Document()

    # 添加样式
    styles = doc.styles

    # 读取 Markdown 文件
    with open(input_file, 'r', encoding='utf-8') as f:
        content = f.read()

    lines = content.split('\n')
    current_list = []
    in_code_block = False
    code_text = []
    in_table = False
    table_rows = []

    for line in lines:
        # 处理代码块
        if line.startswith('```'):
            if in_code_block:
                # 结束代码块
                p = doc.add_paragraph('\n'.join(code_text))
                p.style = 'No Spacing'
                for run in p.runs:
                    run.font.name = 'Consolas'
                    run.font.size = Pt(9)
                code_text = []
                in_code_block = False
            else:
                in_code_block = True
            continue

        if in_code_block:
            code_text.append(line)
            continue

        # 处理表格
        if line.startswith('|') and line.endswith('|'):
            if not in_table:
                in_table = True
                table_rows = []
            table_rows.append([cell.strip() for cell in line.split('|')[1:-1]])
            continue
        elif in_table:
            # 结束表格
            if len(table_rows) > 0:
                # 检查是否为分隔行
                if not all(re.match(r'-+$', cell) for cell in table_rows[0]):
                    table = doc.add_table(rows=len(table_rows), cols=len(table_rows[0]))
                    table.style = 'Table Grid'
                    for i, row in enumerate(table_rows):
                        for j, cell in enumerate(row):
                            table.rows[i].cells[j].text = cell
                in_table = False
                table_rows = []

        # 跳过空行
        if not line.strip():
            continue

        # 处理标题
        if line.startswith('# '):
            doc.add_heading(line[2:], level=1)
        elif line.startswith('## '):
            doc.add_heading(line[3:], level=2)
        elif line.startswith('### '):
            doc.add_heading(line[4:], level=3)
        elif line.startswith('#### '):
            doc.add_heading(line[5:], level=4)
        # 处理列表项
        elif line.startswith('- '):
            p = doc.add_paragraph(line[2:], style='List Bullet')
        # 处理普通段落
        else:
            doc.add_paragraph(line)

    # 处理剩余的表格
    if in_table and len(table_rows) > 0:
        if not all(re.match(r'-+$', cell) for cell in table_rows[0]):
            table = doc.add_table(rows=len(table_rows), cols=len(table_rows[0]))
            table.style = 'Table Grid'
            for i, row in enumerate(table_rows):
                for j, cell in enumerate(row):
                    table.rows[i].cells[j].text = cell

    doc.save(output_file)
    print(f'转换完成：{input_file} -> {output_file}')

if __name__ == '__main__':
    markdown_to_docx('未命名.md', '社媒收单流程.docx')

